  taksit_transfer:{...(tr.taksit_transfer||{n:"Taksit Transfer",i:""}),d:"Ekonomi kartı. Şimdi para verir. COMMON +€4M. DARK +€8M ama başkan güveni -1 ve final cezası taşır."},
