  gecici_prim:{...tr.gecici_prim,d:"Tek maçlık güç. COMMON +6 ve %30 sakatlık riski. DARK +12 ve %60 sakatlık riski. Sonraki maç yorgunluk cezası gelir."},
  kisa_kamp:{...(tr.kisa_kamp||{n:"Kısa Kamp",i:"⛺"}),d:"Tek maçlık kontrollü güç. COMMON +4, sonraki maç -2. DARK +6, sonraki maç -4. En iyi: kritik eşleşme."},
